// Conan Exiles (gameId 65) - AfterCustomModInstalled
// V2: IronPython3 "Copy mod files" (scriptId 371)
// Moves the freshly downloaded workshop files out of the steam download
// location (Dynamic.InstallPath) into ConanSandbox/Mods, records the moved
// file names in {FileId}.txt so the uninstall script can remove them later,
// then rebuilds modlist.txt from every .pak ordered by creation time.
using System;
using System.IO;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string installPath = (string)Dynamic.InstallPath;
string fileId = Convert.ToString(Dynamic.FileId);

string modPath = Path.Combine(ThisService.RootDirectory, "ConanSandbox", "Mods");
Directory.CreateDirectory(modPath);

// Save a list of the mod's files so we can delete them when uninstalling the mod.
string modFileList = Path.Combine(modPath, $"{fileId}.txt");
foreach (string file in Directory.GetFiles(installPath, "*", SearchOption.AllDirectories))
{
    string modFile = Path.Combine(modPath, Path.GetFileName(file));
    if (File.Exists(modFile))
    {
        File.Delete(modFile);
    }
    File.Move(file, modFile);
    File.AppendAllText(modFileList, $"{Path.GetFileName(file)}\r");
}

// Create modlist.txt
string modListTxt = Path.Combine(modPath, "modlist.txt");
if (File.Exists(modListTxt))
{
    File.Delete(modListTxt);
}

var modPathInfo = new DirectoryInfo(modPath);
var pakFiles = modPathInfo.GetFiles("*.pak", SearchOption.AllDirectories)
    .OrderBy(f => f.CreationTime)
    .ToArray();
foreach (var file in pakFiles)
{
    File.AppendAllText(modListTxt, $"{Path.GetFileName(file.FullName)}\r");
}

// Conan Exiles (gameId 65) - AfterCustomModUninstalled
// V2: IronPython3 "Delete mod files" (scriptId 372)
// Reads the {FileId}.txt manifest written by the install script, deletes each
// listed file from ConanSandbox/Mods, removes the manifest, then rebuilds
// modlist.txt from the remaining .pak files ordered by creation time.
using System;
using System.IO;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string fileId = Convert.ToString(Dynamic.FileId);

string modPath = Path.Combine(ThisService.RootDirectory, "ConanSandbox", "Mods");
string modFileList = Path.Combine(modPath, $"{fileId}.txt");

if (File.Exists(modFileList))
{
    string[] modFiles = File.ReadAllLines(modFileList);
    foreach (string entry in modFiles)
    {
        string modFile = Path.Combine(modPath, entry);
        if (File.Exists(modFile))
        {
            File.Delete(modFile);
        }
    }
    File.Delete(modFileList);
}

// Create modlist.txt
string modListTxt = Path.Combine(modPath, "modlist.txt");
if (File.Exists(modListTxt))
{
    File.Delete(modListTxt);
}

var modPathInfo = new DirectoryInfo(modPath);
var pakFiles = modPathInfo.GetFiles("*.pak", SearchOption.AllDirectories)
    .OrderBy(f => f.CreationTime)
    .ToArray();
foreach (var file in pakFiles)
{
    File.AppendAllText(modListTxt, $"{Path.GetFileName(file.FullName)}\r");
}

// Conan Exiles (gameId 65) - AfterCustomModUpdated
// V2: IronPython3 "Moves mod files." (scriptId 373)
// Moves the updated workshop files out of the steam download location
// (Dynamic.InstallPath) into ConanSandbox/Mods and appends each moved file
// name to the {FileId}.txt manifest. Faithful port of the V2 behaviour:
// the manifest is appended to (not recreated) and modlist.txt is NOT rebuilt
// by this event. (The V2 original also tracked the last .pak file name in a
// local that it never used afterwards; that dead assignment is dropped.)
using System;
using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string installPath = (string)Dynamic.InstallPath;
string fileId = Convert.ToString(Dynamic.FileId);

string modPath = Path.Combine(ThisService.RootDirectory, "ConanSandbox", "Mods");
Directory.CreateDirectory(modPath);

// Save a list of the mod's files so we can delete them when uninstalling the mod.
string modFileList = Path.Combine(modPath, $"{fileId}.txt");
foreach (string file in Directory.GetFiles(installPath, "*", SearchOption.AllDirectories))
{
    string modFile = Path.Combine(modPath, Path.GetFileName(file));
    if (File.Exists(modFile))
    {
        File.Delete(modFile);
    }
    File.Move(file, modFile);
    string modFileName = Path.GetFileName(file);
    File.AppendAllText(modFileList, $"{modFileName}\r");
}
